customCss:
.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #e0f7fa;
            margin: 20px 0;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.12);
            padding: 25px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #b2ebf2;
            box-sizing: border-box;
            height: auto;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #00796b;
            padding-bottom: 12px;
            margin-bottom: 12px;
        }
        .single-summary-card .card-header-icon {
            font-size: 34px;
            color: #00796b;
            margin-right: 14px;
        }
        .single-summary-card .card-header h3 {
            font-size: 24px;
            color: #00796b;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            font-size: 16px;
            line-height: 1.65;
            color: #333;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 10px;
        }
        .single-summary-card .card-content strong {
            color: #004d40;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #fff9c4;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
        }
        .single-summary-card .card-content .formula {
            background-color: #e0f7fa;
            padding: 6px 10px;
            border-radius: 4px;
            font-size: 0.9em;
            text-align: center;
            margin-top: 5px;
            color: #004d40;
        }
        .single-summary-card .card-footer {
            font-size: 14px;
            color: #777;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #b2ebf2;
            margin-top: 15px;
        }
